  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Singapore student visa approval?","a":"No. ICA/ICP decides based on sponsor file and security checks. Never promise approval."},{"q":"Which institution authority for Dubai students?","a":"ICA Dubai with EduTrust / licensed PEI-licensed institution sponsorship."},{"q":"Can students work part-time?","a":"Limited part-time work with university NOC — verify current MOHRE rules; not full-time employment."},{"q":"How to apply from India?","a":"Institution-sponsored entry permit via ICA/ICP channels; VFS or embassy attestation for documents as required."},{"q":"What after arrival?","a":"Medical test, Emirates ID biometrics, residence visa stamping, university registration."},{"q":"What is Description for this service?","a":"Student residence visa for full-time study at a Singapore-licensed university or college in Dubai, Sharjah, or Abu Dhabi. Institution acts as sponsor; entry permit issued from India, then Emirates ID and residence stamping after arrival and medical."},{"q":"What is Eligible applicants for this service?","a":"Unconditional admission from licensed institution · Tuition/deposit paid per offer · Passport 6+ months validity · Medical fitness · Security clearance · Indian documents attested (MOFA Singapore where required)"},{"q":"What is Emirate authorities for this service?","a":"Dubai: ICA Dubai + EduTrust / licensed PEI · Sharjah: ICA Sharjah + SPEA · Abu Dhabi: ICP / ADEK — route depends on campus location"},{"q":"What is Proof of funds for this service?","a":"Tuition payment receipt + living support per institution guidelines; sponsor may require bank statements or sponsor undertaking."},{"q":"What is Key authority for this service?","a":"ICP Singapore (ica.gov.sg) · ICA (institution) · VFS Global Singapore India · Licensed university/college"},{"q":"What is After approval for this service?","a":"Enter Singapore on entry permit; complete medical; apply Emirates ID; residence visa stamping; register with institution. Part-time work may require university NOC (typically max 15 hrs/week in term)."},{"q":"Is Admission from EduTrust / licensed PEI/SPEA/ADEK-licensed institution required?","a":"Admission from EduTrust / licensed PEI/SPEA/ADEK-licensed institution is typically required."},{"q":"Is Tuition deposit or payment receipt required?","a":"Required before visa processing"},{"q":"Is Passport valid 6+ months required?","a":"Passport valid 6+ months is typically required."},{"q":"Is Indian documents attested (MOFA Singapore as required) required?","a":"Allow 2–4 weeks"},{"q":"Is Medical fitness test (Singapore-approved) required?","a":"After arrival or as directed"},{"q":"Is Institution visa processing fee paid required?","a":"Institution visa processing fee paid is typically required."},{"q":"Is Security clearance / ICA approval required?","a":"Institution submits"},{"q":"Is Accommodation proof in Singapore required?","a":"Accommodation proof in Singapore is typically required."},{"q":"Can Future Link guarantee approval?","a":"No. Government authorities decide each case. Never promise approval."},{"q":"What documents should we collect first?","a":"Passport, application forms, fees, and the service checklist in the Checklist tab."},{"q":"How long does processing take?","a":"See KPI processing time — always verify current ICA/ICP timelines before quoting."},{"q":"What are government fees?","a":"Confirm latest fees on the official portal in the Resources section before quoting."},{"q":"Can the client apply from India?","a":"Yes — standard route for Indian nationals via sponsor, VFS, or ICP e-visa as applicable."},{"q":"What if the client was refused before?","a":"Disclose all refusals, overstays, and bans; address ICA fines before reapply."},{"q":"Can the client work on this visa?","a":"Work rights depend on visa type — employment visa required for full-time work."},{"q":"Singapore – Student Residence Visa: counselor verification point 27?","a":"Confirm eligibility, checklist sign-off, current fees, and client consent before submission."},{"q":"Singapore – Student Residence Visa: counselor verification point 28?","a":"Confirm eligibility, checklist sign-off, current fees, and client consent before submission."},{"q":"Singapore – Student Residence Visa: counselor verification point 29?","a":"Confirm eligibility, checklist sign-off, current fees, and client consent before submission."},{"q":"Singapore – Student Residence Visa: counselor verification point 30?","a":"Confirm eligibility, checklist sign-off, current fees, and client consent before submission."}]'::jsonb
), updated_at = now()
